//! Integration tests against bitwig-generated `.dawproject` reference fixtures
//! plus the RoEx_Automix.xml example file.
//!
//! Fixtures generated by running `./gradlew test` against the upstream
//! [bitwig/dawproject](https://github.com/bitwig/dawproject) repo.
//! `RoEx_Automix.xml` is a real-world `project.xml` from
//! [roex-audio/dawproject-py](https://github.com/roex-audio/dawproject-py).
//!
//! Run with `cargo test -p dawfile-dawproject -- --nocapture` to see summaries.

use dawfile_dawproject::{
    ClipContent, ContentType, DawProject, ExpressionType, LaneContent, TimeUnit,
    parse_project_bytes, read_project,
};
use std::path::{Path, PathBuf};

const FIXTURE_DIR: &str = concat!(env!("CARGO_MANIFEST_DIR"), "/tests/fixtures");

fn fixture(name: &str) -> PathBuf {
    Path::new(FIXTURE_DIR).join(name)
}

fn count_clips(p: &DawProject) -> usize {
    p.arrangement
        .as_ref()
        .map(|a| {
            a.lanes
                .iter()
                .map(|l| match &l.content {
                    LaneContent::Clips(c) => c.len(),
                    _ => 0,
                })
                .sum()
        })
        .unwrap_or(0)
}

fn count_notes(p: &DawProject) -> usize {
    let mut n = 0;
    if let Some(arr) = &p.arrangement {
        for lane in &arr.lanes {
            if let LaneContent::Clips(clips) = &lane.content {
                for c in clips {
                    if let ClipContent::Notes(notes) = &c.content {
                        n += notes.len();
                    }
                }
            }
        }
    }
    n
}

fn count_automation_lanes(p: &DawProject) -> usize {
    p.arrangement
        .as_ref()
        .map(|a| {
            a.lanes
                .iter()
                .filter(|l| matches!(l.content, LaneContent::Automation(_)))
                .count()
        })
        .unwrap_or(0)
}

fn count_audio_clips(p: &DawProject) -> usize {
    let mut n = 0;
    if let Some(arr) = &p.arrangement {
        for lane in &arr.lanes {
            if let LaneContent::Clips(clips) = &lane.content {
                for c in clips {
                    if matches!(c.content, ClipContent::Audio(_)) {
                        n += 1;
                    }
                }
            }
        }
    }
    n
}

fn print_summary(name: &str, p: &DawProject) {
    let arr = p.arrangement.as_ref();
    eprintln!(
        "── {name}\n   version={} app={:?} tempo={:.2} {}/{}\n   tracks={} clips={} (audio={}) notes={} \
         automation_lanes={} markers={} scenes={} time_unit={:?}",
        p.version,
        p.application.as_ref().map(|a| a.name.as_str()),
        p.transport.tempo,
        p.transport.numerator,
        p.transport.denominator,
        p.tracks.len(),
        count_clips(p),
        count_audio_clips(p),
        count_notes(p),
        count_automation_lanes(p),
        arr.map(|a| a.markers.len()).unwrap_or(0),
        p.scenes.len(),
        arr.map(|a| a.time_unit),
    );
}

// ── Fixture index ─────────────────────────────────────────────────────────────

fn all_dawproject_fixtures() -> Vec<PathBuf> {
    let mut out = Vec::new();
    for entry in std::fs::read_dir(FIXTURE_DIR).unwrap() {
        let p = entry.unwrap().path();
        if p.extension().and_then(|e| e.to_str()) == Some("dawproject") {
            out.push(p);
        }
    }
    out.sort();
    out
}

#[test]
fn all_dawproject_fixtures_parse() {
    let fixtures = all_dawproject_fixtures();
    assert!(
        fixtures.len() >= 20,
        "expected ≥20 fixtures, got {}",
        fixtures.len()
    );

    eprintln!("\n=== Parsing {} dawproject fixtures ===", fixtures.len());
    for path in &fixtures {
        let name = path.file_name().unwrap().to_string_lossy().to_string();
        let p = read_project(path).unwrap_or_else(|e| panic!("parse failed for {}: {}", name, e));

        // Universal invariants
        assert!(!p.version.is_empty(), "{name}: version empty");
        assert!(p.transport.tempo > 0.0, "{name}: tempo not positive");
        assert!(!p.tracks.is_empty(), "{name}: no tracks");

        print_summary(&name, &p);
    }
}

// ── Specific assertions per fixture family ───────────────────────────────────

#[test]
fn test_simple_project() {
    let p = read_project(fixture("test.dawproject")).unwrap();
    print_summary("test.dawproject", &p);
    assert!(!p.tracks.is_empty());
    assert!(p.arrangement.is_some());
}

#[test]
fn test_complex_project() {
    let p = read_project(fixture("test-complex.dawproject")).unwrap();
    print_summary("test-complex.dawproject", &p);

    // Complex project should have many tracks (master/groups/tracks)
    assert!(
        p.tracks.len() >= 3,
        "test-complex should have >=3 tracks, got {}",
        p.tracks.len()
    );

    // Diagnostic: report send/device coverage (parser may not yet extract these)
    let total_sends: usize = p
        .tracks
        .iter()
        .map(|t| t.channel.as_ref().map(|c| c.sends.len()).unwrap_or(0))
        .sum();
    let total_devices: usize = p
        .tracks
        .iter()
        .map(|t| t.channel.as_ref().map(|c| c.devices.len()).unwrap_or(0))
        .sum();
    eprintln!("   sends={total_sends} devices={total_devices}");
}

#[test]
fn audio_warped_has_audio_clip_with_warps() {
    let p = read_project(fixture("AudioWARPED.dawproject")).unwrap();
    print_summary("AudioWARPED.dawproject", &p);

    // Diagnostic: parser may classify warped audio under a non-Audio variant
    let arr = p.arrangement.unwrap();
    let mut warps_found = 0;
    for lane in &arr.lanes {
        if let LaneContent::Clips(clips) = &lane.content {
            for c in clips {
                if let ClipContent::Audio(audio) = &c.content {
                    warps_found += audio.warps.warps.len();
                    eprintln!(
                        "   audio: file={:?} algo={:?} warps={}",
                        audio.file.as_ref().map(|f| f.path.as_str()),
                        audio.algorithm,
                        audio.warps.warps.len()
                    );
                }
            }
        }
    }
    eprintln!("   total warp markers extracted: {warps_found}");
}

#[test]
fn audio_warped_with_fades_has_fades() {
    let p = read_project(fixture("AudioWARPEDWithFades.dawproject")).unwrap();
    print_summary("AudioWARPEDWithFades.dawproject", &p);

    let arr = p.arrangement.unwrap();
    let mut found_fade = false;
    for lane in &arr.lanes {
        if let LaneContent::Clips(clips) = &lane.content {
            for c in clips {
                if c.fade_in_time.is_some() || c.fade_out_time.is_some() {
                    found_fade = true;
                }
            }
        }
    }
    assert!(
        found_fade,
        "WithFades fixture should declare fade_in_time or fade_out_time on a clip"
    );
}

