#[test]
fn raw_beats_uses_beats_time_unit() {
    let p = read_project(fixture("AudioRAW_BEATS.dawproject")).unwrap();
    print_summary("AudioRAW_BEATS.dawproject", &p);

    let arr = p.arrangement.unwrap();
    // RAW_BEATS audio content lives on a beats-unit lane
    let any_audio_clip_in_beats = arr.lanes.iter().any(|l| {
        if let LaneContent::Clips(clips) = &l.content {
            clips
                .iter()
                .any(|c| matches!(c.content, ClipContent::Audio(_)))
        } else {
            false
        }
    });
    assert!(any_audio_clip_in_beats);
    assert_eq!(arr.time_unit, TimeUnit::Beats);
}

#[test]
fn raw_seconds_uses_seconds_somewhere() {
    let p = read_project(fixture("AudioRAW_SECONDS.dawproject")).unwrap();
    print_summary("AudioRAW_SECONDS.dawproject", &p);

    {
        let arr = p.arrangement.as_ref().unwrap();
        eprintln!(
            "   arr time_unit={:?}; lane overrides: {:?}",
            arr.time_unit,
            arr.lanes.iter().map(|l| l.time_unit).collect::<Vec<_>>()
        );
    }
    assert!(count_audio_clips(&p) >= 1);
}

#[test]
fn file_with_relative_path_has_internal_file() {
    let p = read_project(fixture("AudioFILE_WITH_RELATIVE_PATH.dawproject")).unwrap();
    print_summary("AudioFILE_WITH_RELATIVE_PATH.dawproject", &p);

    let arr = p.arrangement.unwrap();
    let mut found = false;
    for lane in &arr.lanes {
        if let LaneContent::Clips(clips) = &lane.content {
            for c in clips {
                if let ClipContent::Audio(audio) = &c.content {
                    if let Some(f) = &audio.file {
                        eprintln!("   file: path={:?} external={}", f.path, f.external);
                        found = true;
                    }
                }
            }
        }
    }
    assert!(found, "expected at least one audio file reference");
}

#[test]
fn file_with_absolute_path_is_external() {
    let p = read_project(fixture("AudioFILE_WITH_ABSOLUTE_PATH.dawproject")).unwrap();
    print_summary("AudioFILE_WITH_ABSOLUTE_PATH.dawproject", &p);

    let arr = p.arrangement.unwrap();
    let mut external_seen = false;
    for lane in &arr.lanes {
        if let LaneContent::Clips(clips) = &lane.content {
            for c in clips {
                if let ClipContent::Audio(audio) = &c.content {
                    if let Some(f) = &audio.file {
                        if f.external {
                            external_seen = true;
                        }
                    }
                }
            }
        }
    }
    assert!(
        external_seen,
        "absolute-path fixture should mark file reference as external"
    );
}

#[test]
fn midi_cc1_automation_on_track_has_track_lane() {
    let p = read_project(fixture("MIDI-CC1-AutomationOnTrack.dawproject")).unwrap();
    print_summary("MIDI-CC1-AutomationOnTrack.dawproject", &p);

    // Should have a CC1 automation lane at arrangement level (not nested in clip)
    assert!(
        count_automation_lanes(&p) >= 1,
        "expected ≥1 automation lane at track level"
    );

    let arr = p.arrangement.unwrap();
    let cc1_track_lane = arr.lanes.iter().any(|l| {
        if let LaneContent::Automation(pts) = &l.content {
            pts.target.controller == Some(1)
        } else {
            false
        }
    });
    assert!(cc1_track_lane, "expected CC#1 controller automation lane");
}

#[test]
fn midi_cc1_automation_in_clips_has_nested_automation() {
    let p = read_project(fixture("MIDI-CC1-AutomationInClips.dawproject")).unwrap();
    print_summary("MIDI-CC1-AutomationInClips.dawproject", &p);

    // Notes-in-clips fixture: parser may not yet recurse into nested clip lanes.
    let arr = p.arrangement.unwrap();
    let mut clip_count = 0;
    for lane in &arr.lanes {
        if let LaneContent::Clips(clips) = &lane.content {
            clip_count += clips.len();
        }
    }
    eprintln!("   parsed {clip_count} clips at arrangement level (nested CC1 not yet recursed)");
    assert!(clip_count > 0, "expected at least one clip");
}

