// ── RoEx_Automix.xml: bare project.xml from a real Studio One workflow ────────

#[test]
fn roex_automix_xml_parses_via_zip_wrap() {
    // RoEx_Automix.xml is a raw project.xml. Wrap it in a ZIP so our reader
    // (which expects a .dawproject zip envelope) can ingest it.
    use std::io::Write;
    use zip::write::SimpleFileOptions;

    let xml = std::fs::read(fixture("RoEx_Automix.xml")).expect("read RoEx_Automix.xml");
    assert!(xml.starts_with(b"<?xml") || xml.starts_with(b"<Project"));

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        zip.start_file("project.xml", SimpleFileOptions::default())
            .unwrap();
        zip.write_all(&xml).unwrap();
        zip.finish().unwrap();
    }

    let p = parse_project_bytes(&buf).expect("parse RoEx_Automix wrapped");
    print_summary("RoEx_Automix.xml (zip-wrapped)", &p);

    assert!(p.transport.tempo > 0.0);
    assert!(!p.tracks.is_empty());
    // Real-world export tends to include both audio and automation.
    let has_audio = p.tracks.iter().any(|t| {
        t.content_types
            .iter()
            .any(|c| matches!(c, ContentType::Audio))
    });
    assert!(has_audio, "expected at least one Audio track in RoEx mix");
}

// ── Stress: parse → reserialize → reparse all fixtures ────────────────────────

#[test]
fn fixtures_round_trip_through_serializer() {
    use dawfile_dawproject::serialize_project_bytes;

    for path in all_dawproject_fixtures() {
        let name = path.file_name().unwrap().to_string_lossy().to_string();
        let original = read_project(&path).unwrap_or_else(|e| panic!("read {name}: {e}"));
        let bytes =
            serialize_project_bytes(&original).unwrap_or_else(|e| panic!("serialize {name}: {e}"));
        let restored =
            parse_project_bytes(&bytes).unwrap_or_else(|e| panic!("re-parse {name}: {e}"));

        // Track count must survive round-trip
        assert_eq!(
            restored.tracks.len(),
            original.tracks.len(),
            "{name}: track count changed across round-trip"
        );
        assert!(
            (restored.transport.tempo - original.transport.tempo).abs() < 0.001,
            "{name}: tempo drifted across round-trip"
        );
    }
}
